body:
Here is the simplest example I could come up with:
```verilog
timeunit 1ns/1ns;

class Foo;
    event write_events[int];

    function void add_event(int index, event in);
        write_events[index] = in;
    endfunction

    task trigger_event(int index);
        ->write_events[index];
    endtask

    function void delete_event(int index);
        write_events.delete(index);
    endfunction
endclass

class Bar;
    Foo foo;
    event baz;

    function new(Foo foo);
        this.foo = foo;
    endfunction

    task go();
        foo.add_event(3, baz);
        @baz;
        $display("got here");
        foo.delete_event(3);
    endtask
endclass

module top;
    Bar bar;
    Foo foo;

    initial begin
        foo = new();
        bar = new(foo);
        bar.go();
    end

    initial begin
        #10;
        foo.trigger_event(3);
    end

endmodule
```
Works fine if `write_events` is a single `event` instead of an associative array of events.  Works fine as an associative array in other simulators.

